-- ============================================================
-- 마일리지 balance_after 재계산
-- ============================================================
UPDATE customer_mileage cm
INNER JOIN (
  SELECT mileage_id,
    @bal:=IF(@pc=customer_id,@bal+IF(type IN('EARN','ADJUST'),amount,-amount),IF(type IN('EARN','ADJUST'),amount,-amount)) AS cb,
    @pc:=customer_id AS _p
  FROM customer_mileage,(SELECT @bal:=0,@pc:=0) v
  WHERE company_id=@company_id ORDER BY customer_id,created_at,mileage_id
) c ON cm.mileage_id=c.mileage_id SET cm.balance_after=GREATEST(c.cb,0);

UPDATE customers c INNER JOIN (
  SELECT customer_id,balance_after FROM customer_mileage cm1
  WHERE mileage_id=(SELECT MAX(cm2.mileage_id) FROM customer_mileage cm2 WHERE cm2.customer_id=cm1.customer_id)
) l ON c.customer_id=l.customer_id SET c.mileage_balance=l.balance_after WHERE c.company_id=@company_id;

UPDATE customers SET mileage_balance=0 WHERE company_id=@company_id AND customer_id NOT IN(SELECT DISTINCT customer_id FROM customer_mileage WHERE company_id=@company_id);

-- ============================================================
-- 최종 확인
-- ============================================================
SELECT '운행' AS item,COUNT(*) AS cnt FROM rides WHERE company_id=@company_id UNION ALL SELECT '마일리지 거래',COUNT(*) FROM customer_mileage WHERE company_id=@company_id UNION ALL SELECT '마일리지 보유 고객',COUNT(*) FROM customers WHERE company_id=@company_id AND mileage_balance>0 UNION ALL SELECT CONCAT('총 마일리지: ',FORMAT(SUM(mileage_balance),0),'원'),COUNT(*) FROM customers WHERE company_id=@company_id;

